package validsuites

func SayHello(name string) string {
	return "Hello " + name
}

func SayGoodbye(name string) string {
	return "Goodbye " + name
}

func SayGoodMorning(name string) string {
	return "Good morning " + name
}

func SayGoodAfternoon(name string) string {
	return "Good afternoon " + name
}
